package com.baize.flux.server.http; import com.baize.flux.server.http.servlet.*; import com.baize.flux.server.service.JobRestService; import org.eclipse.jetty.server.*; import org.eclipse.jetty.servlet.*;
/** 仅负责嵌入式 Jetty 生命周期和路由装配。 */ public final class JettyServer {private final Server server; public JettyServer(String host,int port,JobRestService service){server=new Server();ServerConnector c=new ServerConnector(server);c.setHost(host);c.setPort(port);server.addConnector(c);ServletContextHandler h=new ServletContextHandler(ServletContextHandler.NO_SESSIONS);h.setContextPath("/");h.addServlet(new ServletHolder(new HealthServlet(service)),"/api/v1/health");h.addServlet(new ServletHolder(new JobsServlet(service)),"/api/v1/jobs");h.addServlet(new ServletHolder(new JobInfoServlet(service)),"/api/v1/jobs/*");server.setHandler(h);} public void start()throws Exception{server.start();} public void join()throws InterruptedException{server.join();} public void stop()throws Exception{server.stop();}}
